const input = $input.first().json;

const data =
  input.body && Object.keys(input.body).length > 0
    ? input.body
    : input.query && Object.keys(input.query).length > 0
      ? input.query
      : input;

function clean(value, fallback = "") {
  if (value === undefined || value === null) return fallback;
  return String(value).trim();
}

function toNumber(value) {
  const number = Number(value);
  return Number.isFinite(number) ? number : 0;
}

const now = Date.now();

const applicationId = clean(data.application_id || data.applicationId, "FIN-APP-" + now);
const reviewId = "FIN-REV-" + now;

const documentos = data.documentos || {};

return [
  {
    json: {
      review_id: reviewId,
      application_id: applicationId,
      nombre: clean(data.nombre || data.name),
      email: clean(data.email || data.correo).toLowerCase(),
      telefono: clean(data.telefono || data.phone || data.celular),
      ciudad: clean(data.ciudad || data.city),
      tipo_propiedad: clean(data.tipo_propiedad || data.property_type, "Otro"),
      valor_propiedad: toNumber(data.valor_propiedad || data.property_value),
      enganche_disponible: toNumber(data.enganche_disponible || data.down_payment),
      ingreso_mensual: toNumber(data.ingreso_mensual || data.monthly_income),
      plazo_deseado_anios: toNumber(data.plazo_deseado_anios || data.plazo_deseado_años || data.term_years),
      antiguedad_laboral_anios: toNumber(data.antiguedad_laboral_anios || data.antiguedad_laboral_años || data.work_seniority_years),
      score_crediticio: toNumber(data.score_crediticio || data.credit_score),
      documentos: {
        identificacion_oficial: Boolean(documentos.identificacion_oficial),
        comprobante_domicilio: Boolean(documentos.comprobante_domicilio),
        comprobante_ingresos: Boolean(documentos.comprobante_ingresos),
        estados_cuenta: Boolean(documentos.estados_cuenta),
        rfc: Boolean(documentos.rfc),
        curp: Boolean(documentos.curp),
        documentos_propiedad: Boolean(documentos.documentos_propiedad)
      },
      mensaje: clean(data.mensaje || data.message),
      fecha_revision: new Date().toISOString().slice(0, 10),
      folder_name: `FINANCING_REVIEW_${reviewId}_${clean(data.nombre || data.name, "Sin nombre")}`,
      json_original: JSON.stringify(data)
    }
  }
];

const item = $input.first().json;
const errores = [];

if (!item.nombre || item.nombre.length < 2) {
  errores.push("Nombre inválido o vacío");
}

if (!item.email || !item.email.includes("@")) {
  errores.push("Email inválido o vacío");
}

if (!item.telefono || item.telefono.length < 7) {
  errores.push("Teléfono inválido o vacío");
}

if (!item.ciudad || item.ciudad.length < 2) {
  errores.push("Ciudad inválida o vacía");
}

if (!item.valor_propiedad || item.valor_propiedad <= 0) {
  errores.push("Valor de propiedad inválido");
}

if (!item.ingreso_mensual || item.ingreso_mensual <= 0) {
  errores.push("Ingreso mensual inválido");
}

if (!item.plazo_deseado_anios || item.plazo_deseado_anios <= 0) {
  errores.push("Plazo deseado inválido");
}

if (item.score_crediticio && (item.score_crediticio < 300 || item.score_crediticio > 850)) {
  errores.push("Score crediticio fuera de rango");
}

if (!item.mensaje || item.mensaje.length < 5) {
  errores.push("Mensaje inválido o vacío");
}

return [
  {
    json: {
      ...item,
      valido: errores.length === 0,
      errores_validacion: errores
    }
  }
];

const base = $node["Validar Datos del Solicitante"].json;
const search = $node["Buscar Revisión en Airtable"].json;

return [
  {
    json: {
      ...base,
      existing_review: true,
      existing_airtable_record_id: search.records?.[0]?.id || null
    }
  }
];

const base = $node["Validar Datos del Solicitante"].json;

return [
  {
    json: {
      ...base,
      existing_review: false,
      existing_airtable_record_id: null
    }
  }
];

const base = $node["Validar Datos del Solicitante"].json;
const docs = base.documentos || {};

const labels = {
  identificacion_oficial: "Identificación oficial",
  comprobante_domicilio: "Comprobante de domicilio",
  comprobante_ingresos: "Comprobante de ingresos",
  estados_cuenta: "Estados de cuenta",
  rfc: "RFC",
  curp: "CURP",
  documentos_propiedad: "Documentos de propiedad"
};

const checklist = {};
let completos = 0;
const faltantes = [];

for (const [key, label] of Object.entries(labels)) {
  const recibido = Boolean(docs[key]);
  if (recibido) {
    completos += 1;
  } else {
    faltantes.push(label);
  }

  checklist[key] = {
    checklist_id: `CHK-${base.review_id}-${key}`.slice(0, 80),
    documento: label,
    requerido: true,
    recibido,
    estado: recibido ? "Recibido" : "Pendiente",
    comentario: recibido ? "Documento marcado como recibido." : "Documento pendiente de recibir."
  };
}

const total = Object.keys(labels).length;
const porcentaje = Number(((completos / total) * 100).toFixed(2));

return [
  {
    json: {
      ...base,
      expediente_url: "https://drive.google.com/drive/folders/" + $node["Crear Carpeta Principal Google Drive"].json.id,
      carpeta_drive_id: $node["Crear Carpeta Principal Google Drive"].json.id,
      documentos_completos: completos,
      documentos_faltantes: faltantes,
      documentos_faltantes_texto: faltantes.length ? faltantes.join(", ") : "Sin documentos faltantes",
      porcentaje_documentos_completos: porcentaje,
      document_checklist: checklist
    }
  }
];

const item = $node["Evaluar Checklist Documental"].json;

const valor = Number(item.valor_propiedad || 0);
const enganche = Number(item.enganche_disponible || 0);
const ingreso = Number(item.ingreso_mensual || 0);
const plazo = Number(item.plazo_deseado_anios || 0);
const scoreCrediticio = Number(item.score_crediticio || 0);
const antiguedad = Number(item.antiguedad_laboral_anios || 0);

const montoFinanciar = Math.max(valor - enganche, 0);
const porcentajeEnganche = valor > 0 ? Number(((enganche / valor) * 100).toFixed(2)) : 0;

const annualRate = 0.12;
const monthlyRate = annualRate / 12;
const months = plazo * 12;

let pagoMensual = 0;
if (montoFinanciar > 0 && months > 0) {
  pagoMensual = montoFinanciar * monthlyRate / (1 - Math.pow(1 + monthlyRate, -months));
}
pagoMensual = Number(pagoMensual.toFixed(2));

const relacionPagoIngreso = ingreso > 0 ? Number(((pagoMensual / ingreso) * 100).toFixed(2)) : 0;

let scoreInterno = 50;

if (porcentajeEnganche >= 20) scoreInterno += 15;
else if (porcentajeEnganche >= 10) scoreInterno += 7;
else scoreInterno -= 10;

if (relacionPagoIngreso <= 35) scoreInterno += 20;
else if (relacionPagoIngreso <= 45) scoreInterno += 10;
else scoreInterno -= 15;

if (scoreCrediticio >= 720) scoreInterno += 15;
else if (scoreCrediticio >= 650) scoreInterno += 8;
else if (scoreCrediticio > 0) scoreInterno -= 10;

if (antiguedad >= 2) scoreInterno += 5;
else scoreInterno -= 5;

scoreInterno += Math.round(item.porcentaje_documentos_completos * 0.15);

scoreInterno = Math.max(0, Math.min(100, scoreInterno));

let nivelRiesgo = "Medio";
let resultadoRevision = "Revisión manual requerida";
let prioridad = "Media";
let tipoTarea = "Revisión manual";
let diasSeguimiento = 2;

if (scoreInterno >= 80 && item.porcentaje_documentos_completos >= 85 && relacionPagoIngreso <= 35) {
  nivelRiesgo = "Bajo";
  resultadoRevision = "Preaprobación recomendada";
  prioridad = "Media";
  tipoTarea = "Preaprobación";
  diasSeguimiento = 2;
} else if (scoreInterno >= 60 && relacionPagoIngreso <= 50) {
  nivelRiesgo = "Medio";
  resultadoRevision = "Revisión manual requerida";
  prioridad = item.documentos_faltantes.length > 0 ? "Alta" : "Media";
  tipoTarea = "Revisión manual";
  diasSeguimiento = 1;
} else {
  nivelRiesgo = "Alto";
  resultadoRevision = "Análisis especial requerido";
  prioridad = "Alta";
  tipoTarea = "Análisis especial";
  diasSeguimiento = 0;
}

const fecha = new Date();
fecha.setDate(fecha.getDate() + diasSeguimiento);

return [
  {
    json: {
      ...item,
      monto_financiar: montoFinanciar,
      porcentaje_enganche: porcentajeEnganche,
      pago_estimado_mensual: pagoMensual,
      relacion_pago_ingreso: relacionPagoIngreso,
      score_interno: scoreInterno,
      nivel_riesgo_calculado: nivelRiesgo,
      resultado_revision_calculado: resultadoRevision,
      prioridad_calculada: prioridad,
      tipo_tarea: tipoTarea,
      fecha_sugerida_seguimiento: fecha.toISOString().slice(0, 10)
    }
  }
];

