const calc = $node["Calcular Score Financiero"].json;
const ai = $node["OpenAI - Analizar Riesgo"].json;

let text = "";

if (ai.output_text) {
  text = ai.output_text;
} else if (ai.output?.[0]?.content?.[0]?.text) {
  text = ai.output[0].content[0].text;
} else if (ai.choices?.[0]?.message?.content) {
  text = ai.choices[0].message.content;
}

let parsed;
try {
  parsed = JSON.parse(text);
} catch (error) {
  parsed = {
    nivel_riesgo: calc.nivel_riesgo_calculado,
    resultado_revision: calc.resultado_revision_calculado,
    prioridad: calc.prioridad_calculada,
    resumen_ia: "No se pudo parsear correctamente la respuesta de IA. Se usó la evaluación calculada por reglas.",
    siguiente_accion: "Revisar manualmente el caso y solicitar documentos faltantes.",
    comentarios_riesgo: "Respuesta de IA no parseable."
  };
}

return [
  {
    json: {
      ...calc,
      nivel_riesgo: parsed.nivel_riesgo || calc.nivel_riesgo_calculado,
      resultado_revision: parsed.resultado_revision || calc.resultado_revision_calculado,
      prioridad: parsed.prioridad || calc.prioridad_calculada,
      resumen_ia: parsed.resumen_ia || "",
      siguiente_accion: parsed.siguiente_accion || "",
      comentarios_riesgo: parsed.comentarios_riesgo || "",
      task_id: "RISK-TASK-" + Date.now(),
      ai_raw_response: JSON.stringify(ai)
    }
  }
];

const item = $node["Generar Resumen Interno"].json;

function esc(value) {
  return String(value ?? "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

function csvEscape(value) {
  const text = String(value ?? "");
  if (text.includes(",") || text.includes("\n") || text.includes('"')) {
    return '"' + text.replace(/"/g, '""') + '"';
  }
  return text;
}

function csvFromRows(rows) {
  return "\ufeff" + rows.map(row => row.map(csvEscape).join(",")).join("\n");
}

function wordHtml(title, sections) {
  const body = sections.map(section => {
    const rows = section.rows.map(([field, value]) =>
      `<tr><td><strong>${esc(field)}</strong></td><td>${esc(value)}</td></tr>`
    ).join("");

    return `
      <h2>${esc(section.title)}</h2>
      <table border="1" cellspacing="0" cellpadding="6" style="border-collapse:collapse;width:100%;font-family:Arial;font-size:11pt;">
        ${rows}
      </table>
    `;
  }).join("<br>");

  return `<!DOCTYPE html>
<html>
<head>
<meta charset="utf-8">
<title>${esc(title)}</title>
</head>
<body style="font-family:Arial, sans-serif; font-size:11pt;">
<h1>${esc(title)}</h1>
<p><strong>Review ID:</strong> ${esc(item.review_id)}</p>
<p><strong>Application ID:</strong> ${esc(item.application_id)}</p>
${body}
<p style="margin-top:24px;font-size:10pt;"><em>Documento generado automáticamente por n8n. Esta revisión es demostrativa y no representa una aprobación crediticia final.</em></p>
</body>
</html>`;
}

const commonRows = [
  ["Review ID", item.review_id],
  ["Application ID", item.application_id],
  ["Nombre", item.nombre],
  ["Email", item.email],
  ["Teléfono", item.telefono],
  ["Ciudad", item.ciudad],
  ["Fecha de revisión", item.fecha_revision]
];

const folders = [
  {
    folderLabel: "01 - Identificacion",
    folderId: $node["Crear Subcarpeta 01 - Identificacion"].json.id,
    baseName: "01_identificacion",
    title: "Reporte de Identificación del Solicitante",
    rows: [
      ...commonRows,
      ["Identificación oficial", item.documentos?.identificacion_oficial ? "Recibida" : "Pendiente"],
      ["Comprobante de domicilio", item.documentos?.comprobante_domicilio ? "Recibido" : "Pendiente"],
      ["RFC", item.documentos?.rfc ? "Recibido" : "Pendiente"],
      ["CURP", item.documentos?.curp ? "Recibida" : "Pendiente"],
      ["Comentario", "Validación documental básica para identificación del prospecto."]
    ]
  },
  {
    folderLabel: "02 - Ingresos",
    folderId: $node["Crear Subcarpeta 02 - Ingresos"].json.id,
    baseName: "02_ingresos",
    title: "Reporte de Ingresos y Capacidad de Pago",
    rows: [
      ...commonRows,
      ["Ingreso mensual", item.ingreso_mensual],
      ["Antigüedad laboral años", item.antiguedad_laboral_anios],
      ["Score crediticio", item.score_crediticio],
      ["Pago estimado mensual", item.pago_estimado_mensual],
      ["Relación pago-ingreso", `${item.relacion_pago_ingreso}%`],
      ["Comprobante de ingresos", item.documentos?.comprobante_ingresos ? "Recibido" : "Pendiente"],
      ["Resultado", item.resultado_revision]
    ]
  },
  {
    folderLabel: "03 - Estados de Cuenta",
    folderId: $node["Crear Subcarpeta 03 - Estados de Cuenta"].json.id,
    baseName: "03_estados_cuenta",
    title: "Reporte de Estados de Cuenta",
    rows: [
      ...commonRows,
      ["Estados de cuenta", item.documentos?.estados_cuenta ? "Recibidos" : "Pendientes"],
      ["Documentos completos", `${item.documentos_completos}/7`],
      ["Porcentaje documentos completos", `${item.porcentaje_documentos_completos}%`],
      ["Documentos faltantes", item.documentos_faltantes_texto],
      ["Siguiente acción", item.siguiente_accion]
    ]
  },
  {
    folderLabel: "04 - Documentos de Propiedad",
    folderId: $node["Crear Subcarpeta 04 - Documentos de Propiedad"].json.id,
    baseName: "04_propiedad",
    title: "Reporte de Propiedad y Financiamiento",
    rows: [
      ...commonRows,
      ["Tipo de propiedad", item.tipo_propiedad],
      ["Valor propiedad", item.valor_propiedad],
      ["Enganche disponible", item.enganche_disponible],
      ["Monto a financiar", item.monto_financiar],
      ["Porcentaje enganche", `${item.porcentaje_enganche}%`],
      ["Documentos de propiedad", item.documentos?.documentos_propiedad ? "Recibidos" : "Pendientes"]
    ]
  },
  {
    folderLabel: "05 - Revision Interna",
    folderId: $node["Crear Subcarpeta 05 - Revision Interna"].json.id,
    baseName: "05_revision_interna",
    title: "Reporte Interno de Riesgo y Decisión Operativa",
    rows: [
      ...commonRows,
      ["Score interno", item.score_interno],
      ["Nivel de riesgo", item.nivel_riesgo],
      ["Resultado revisión", item.resultado_revision],
      ["Prioridad", item.prioridad],
      ["Resumen IA", item.resumen_ia],
      ["Comentarios de riesgo", item.comentarios_riesgo],
      ["Siguiente acción", item.siguiente_accion]
    ]
  }
];

const output = [];

for (const folder of folders) {
  const wordName = `${folder.baseName}_${item.review_id}.doc`;
  const wordContent = wordHtml(folder.title, [{ title: folder.folderLabel, rows: folder.rows }]);
  output.push({
    json: {
      review_id: item.review_id,
      application_id: item.application_id,
      folder_label: folder.folderLabel,
      folder_id: folder.folderId,
      file_name: wordName,
      file_type: "word-compatible-doc"
    },
    binary: {
      data: {
        data: Buffer.from(wordContent, "utf8").toString("base64"),
        mimeType: "application/msword",
        fileName: wordName
      }
    }
  });

  const csvName = `${folder.baseName}_${item.review_id}.csv`;
  const csvContent = csvFromRows([["Campo", "Valor"], ...folder.rows]);
  output.push({
    json: {
      review_id: item.review_id,
      application_id: item.application_id,
      folder_label: folder.folderLabel,
      folder_id: folder.folderId,
      file_name: csvName,
      file_type: "excel-compatible-csv"
    },
    binary: {
      data: {
        data: Buffer.from(csvContent, "utf8").toString("base64"),
        mimeType: "text/csv",
        fileName: csvName
      }
    }
  });
}

return output;

const base = $node["Generar Resumen Interno"].json;
const uploaded = $input.all().map((item, index) => {
  const fileId = item.json.id || item.json.fileId || null;
  const name = item.json.name || item.json.file_name || item.json.originalFilename || `reporte_${index + 1}`;
  return {
    file_name: name,
    file_id: fileId,
    file_url: item.json.webViewLink || (fileId ? `https://drive.google.com/file/d/${fileId}` : null)
  };
});

return [
  {
    json: {
      ...base,
      report_files: uploaded,
      report_files_count: uploaded.length,
      word_reports_count: uploaded.filter(file => String(file.file_name).toLowerCase().endsWith(".doc")).length,
      excel_reports_count: uploaded.filter(file => String(file.file_name).toLowerCase().endsWith(".csv")).length,
      report_files_urls_text: uploaded.map(file => `${file.file_name}: ${file.file_url || "Sin URL"}`).join("\n")
    }
  }
];
